```class Solution {
    public long findMaximumNumber(long k, int x) {
        long res = 0;
        for (long i = 1; i <= k; i++) {
            long price = 0;
            long num = i;
            while (num > 0) {
                if ((num & x) != 0) {
                    price++;
                }
                num >>= 1;
            }
            if (price * (i + 1) / 2 <= k) {
                res = i;
            } else {
                break;
            }
        }
        return res;
    }
}```
